   "era": "World War II",
   "branch": "Navy",
   "branchLabel": "U.S. Navy – World War II",
   "lat": null,
   "lng": null,
   "photo": "",
   "extraPhotos": [],
   "narrative": "Roderique Dolar Vezina of Holyoke served as a Fireman Second Class in the United States Navy. His station was in the fire rooms below the armored deck, tending the boilers that gave the ship her speed — the hottest, loudest compartment aboard, and the one from which a man had the farthest to climb. He died in his country's service. He was survived by his mother, Mrs. Mary Vezina. If you have further information about this veteran, please contact the City of Holyoke Veterans Graves Officer at (413) 322-5630 at 310 Appleton Street, 1st Floor, Holyoke, MA 01040.",
   "badges": [],
